esqlQuery.esql:
FROM metrics-vcenterreceiver.otel-*
// Datacenter host count by power_state: off or standby indicates problems
// May indicate hardware failure or unplanned maintenance
// Excludes "on" and "unknown"; adjust if unknown should be included
| WHERE vcenter.datacenter.host.count IS NOT NULL
  AND attributes.power_state IN ("off", "standby")
  AND vcenter.datacenter.host.count > 0
| STATS host_count = MAX(vcenter.datacenter.host.count) BY vcenter.datacenter.name, attributes.power_state
| SORT host_count DESC
| LIMIT 20
